{% extends "base.html" %}

{% block content %}
<div id="chat-app" class="flex-1 flex flex-col max-w-3xl mx-auto w-full p-4">
  <div id="messages" class="flex-1 overflow-y-auto space-y-3 mb-4">
    <div class="text-center text-gray-500 text-sm py-4">Connect to start chatting</div>
  </div>

  <form id="chat-form" class="flex gap-2">
    <input id="message-input" type="text" autocomplete="off"
           class="flex-1 border border-gray-300 rounded-lg px-3 py-2 focus:outline-none focus:ring-2 focus:ring-blue-500"
           placeholder="Type a message...">
    <button type="submit"
            class="bg-blue-600 text-white px-4 py-2 rounded-lg hover:bg-blue-700">Send</button>
  </form>
</div>

<script>
(function () {
  const messagesEl = document.getElementById('messages');
  const form = document.getElementById('chat-form');
  const input = document.getElementById('message-input');

  const wsUrl = (location.protocol === 'https:' ? 'wss:' : 'ws:') + '//' + location.host + '/ws/chat/';
  const socket = new WebSocket(wsUrl);

  let assistantBubble = null;

  function appendBubble(type, text) {
    const div = document.createElement('div');
    div.className = 'p-3 rounded-lg ' + (type === 'user'
      ? 'bg-blue-100 self-end ml-auto'
      : 'bg-white border border-gray-200 self-start');
    div.textContent = text;
    messagesEl.appendChild(div);
    messagesEl.scrollTop = messagesEl.scrollHeight;
    return div;
  }

  socket.onopen = function () {
    messagesEl.innerHTML = '';
    appendBubble('assistant', 'Connected. Say something!');
  };

  socket.onmessage = function (event) {
    const data = JSON.parse(event.data);
    if (data.type === 'user') {
      appendBubble('user', data.content);
      assistantBubble = null;
    } else if (data.type === 'assistant_start') {
      assistantBubble = appendBubble('assistant', '');
    } else if (data.type === 'token') {
      if (!assistantBubble) assistantBubble = appendBubble('assistant', '');
      assistantBubble.textContent += data.content;
      messagesEl.scrollTop = messagesEl.scrollHeight;
    } else if (data.type === 'assistant_end') {
      assistantBubble = null;
    } else if (data.type === 'error') {
      appendBubble('assistant', 'Error: ' + data.content);
      assistantBubble = null;
    }
  };

  socket.onclose = function () {
    appendBubble('assistant', 'Disconnected.');
  };

  form.addEventListener('submit', function (e) {
    e.preventDefault();
    const text = input.value.trim();
    if (!text || socket.readyState !== WebSocket.OPEN) return;
    socket.send(JSON.stringify({ message: text }));
    input.value = '';
  });
})();
</script>
{% endblock %}
